import { useBlockProps } from '@wordpress/block-editor';
import { colourVar, fontSizeVar } from '../../utils';

/**
 * Check whether a value string represents a number.
 * Strips commas and whitespace before testing.
 *
 * @param {string} val The value to test.
 * @return {boolean} True if numeric.
 */
function isNumeric( val ) {
	if ( ! val ) {
		return false;
	}
	const cleaned = val.replace( /[,\s]/g, '' );
	return ! isNaN( cleaned ) && cleaned.length > 0;
}

/**
 * Parse a display value like "5,000" into a plain integer.
 *
 * @param {string} val The display value.
 * @return {number} The parsed integer.
 */
function parseDisplayNumber( val ) {
	return parseInt( val.replace( /[,\s]/g, '' ), 10 );
}

export default function Save( { attributes } ) {
	const {
		items,
		animated,
		showItemIcons,
		dividers,
		valueColour,
		labelColour,
		labelFontSize,
		labelFontSizeTablet,
		labelFontSizeMobile,
		hoverBackgroundColour,
		hoverTextColour,
		hoverBorderColour,
		transitionDuration,
		transitionEasing,
	} = attributes;

	const wrapperStyle = {
		'--sgs-hover-bg': hoverBackgroundColour ? colourVar( hoverBackgroundColour ) : undefined,
		'--sgs-hover-text': hoverTextColour ? colourVar( hoverTextColour ) : undefined,
		'--sgs-hover-border': hoverBorderColour ? colourVar( hoverBorderColour ) : undefined,
		'--sgs-transition-duration': transitionDuration ? `${ transitionDuration }ms` : undefined,
		'--sgs-transition-easing': transitionEasing || undefined,
	};

	// Responsive label font-size data-attributes for CSS media query selectors.
	const responsiveDataAttrs = {};
	if ( labelFontSizeTablet ) {
		responsiveDataAttrs[ 'data-label-fs-tablet' ] = labelFontSizeTablet;
	}
	if ( labelFontSizeMobile ) {
		responsiveDataAttrs[ 'data-label-fs-mobile' ] = labelFontSizeMobile;
	}

	const wrapperClass = [
		'sgs-trust-bar',
		dividers ? 'sgs-trust-bar--dividers' : '',
	].filter( Boolean ).join( ' ' );

	const blockProps = useBlockProps.save( {
		className: wrapperClass,
		style: wrapperStyle,
		...responsiveDataAttrs,
	} );

	const valueStyle = {
		color: colourVar( valueColour ) || undefined,
	};

	const labelStyle = {
		color: colourVar( labelColour ) || undefined,
		fontSize: fontSizeVar( labelFontSize ) || undefined,
	};

	return (
		<div { ...blockProps }>
			{ items.map( ( item, index ) => {
				const shouldAnimate =
					animated && item.animated !== false && isNumeric( item.value );

				const dataAttrs = {};
				if ( shouldAnimate ) {
					dataAttrs[ 'data-target' ] = parseDisplayNumber(
						item.value
					);
					dataAttrs[ 'data-separator' ] = 'true';
					if ( item.suffix ) {
						dataAttrs[ 'data-suffix' ] = item.suffix;
					}
				}

				return (
					<div key={ index } className="sgs-trust-bar__item">
						{ showItemIcons && item.icon && (
							<span
								className="sgs-trust-bar__icon"
								data-icon={ item.icon }
								aria-hidden="true"
							/>
						) }
						<span className="sgs-sr-only">
							{ item.value }{ item.suffix } { item.label }
						</span>
						<span
							className="sgs-trust-bar__value"
							style={ valueStyle }
							aria-hidden="true"
							{ ...dataAttrs }
						>
							{ item.value }
							{ item.suffix }
						</span>
						<span
							className="sgs-trust-bar__label"
							style={ labelStyle }
							aria-hidden="true"
						>
							{ item.label }
						</span>
					</div>
				);
			} ) }
		</div>
	);
}
